import { generateCarReportPdf } from "@/lib/genreportpdf";
import { NextResponse } from "next/server";

export const runtime = "nodejs";

export async function GET(
  req: Request,
  ctx: { params: Promise<{ carId: string; checkId: string }> }
) {
  try {
    const params = await ctx.params;
    return await generateCarReportPdf(req, params);
  } catch (e: any) {
    // ✅ ให้เห็น error จริงใน browser console ด้วย
    console.error("REPORT.PDF ROUTE ERROR:", e);
    return NextResponse.json(
      {
        message: e?.message || "Internal Server Error",
        name: e?.name,
        // dev เท่านั้น (ถ้ากลัว production ก็ลบ stack ออก)
        stack: e?.stack,
      },
      { status: 500 }
    );
  }
}
